const now = new Date();
const d2m = new Date(now); d2m.setDate(now.getDate() - 60);
const fmt = d => parseInt(`${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}`);
return [{ json: { fecha: fmt(d2m), rango: 3 } }];

